#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>

#define SESSION_TIMEOUT 300 // 5 minutes
#define MAX_SESSIONS 1000

typedef struct {
    char session_id[33];
    char *data;
    time_t last_access;
    int valid;
} Session;

Session session_cache[MAX_SESSIONS];

void init_sessions() {
    for (int i = 0; i < MAX_SESSIONS; i++) {
        session_cache[i].session_id[0] = '\0';
        session_cache[i].data = NULL;
        session_cache[i].last_access = 0;
        session_cache[i].valid = 0;
    }
}

int find_session_index(const char *session_id) {
    for (int i = 0; i < MAX_SESSIONS; i++) {
        if (session_cache[i].valid && strcmp(session_cache[i].session_id, session_id) == 0) {
            return i;
        }
    }
    return -1;
}

void create_session(const char *session_id, const char *data) {
    int index = find_session_index(session_id);
    if (index == -1) {
        for (int i = 0; i < MAX_SESSIONS; i++) {
            if (!session_cache[i].valid) {
                strncpy(session_cache[i].session_id, session_id, 32);
                session_cache[i].session_id[32] = '\0';
                session_cache[i].data = strdup(data);
                session_cache[i].last_access = time(NULL);
                session_cache[i].valid = 1;
                break;
            }
        }
    } else {
        free(session_cache[index].data);
        session_cache[index].data = strdup(data);
        session_cache[index].last_access = time(NULL);
    }
}

char* access_session(const char *session_id) {
    int index = find_session_index(session_id);
    if (index != -1 && session_cache[index].valid) {
        if (difftime(time(NULL), session_cache[index].last_access) < SESSION_TIMEOUT) {
            session_cache[index].last_access = time(NULL);
            return session_cache[index].data;
        } else {
            free(session_cache[index].data);
            session_cache[index].data = NULL;
            session_cache[index].valid = 0;
        }
    }
    return NULL;
}

void invalidate_session(const char *session_id) {
    int index = find_session_index(session_id);
    if (index != -1) {
        free(session_cache[index].data);
        session_cache[index].data = NULL;
        session_cache[index].valid = 0;
    }
}

void cleanup_expired_sessions() {
    for (int i = 0; i < MAX_SESSIONS; i++) {
        if (session_cache[i].valid && difftime(time(NULL), session_cache[i].last_access) >= SESSION_TIMEOUT) {
            free(session_cache[i].data);
            session_cache[i].data = NULL;
            session_cache[i].valid = 0;
        }
    }
}

